arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0 and life>0
  {
    if introAnim>=100 //Normal behavior
    {
      if initDir=0
      {
        xVel=runAcc
        if x>oPlayer1.x
          xVel*=-1
        initDir=1
      }
      
      if x>oPlayer1.x and image_xscale=1
        turnTime+=1
      else if x<oPlayer1.x and image_xscale=-1
        turnTime+=1
      if turnTime>=25
      {
        sprite_index=sVaultPantherLookBack
        if xVel>0 {xVel-=0.33}
        else if xVel<0 {xVel+=0.33}
        
        if xVel>=-1 and xVel<=1
        {
          if image_xscale=1 {xVel=-runAcc}
          else {xVel=runAcc}
          sprite_index=sVaultPantherRun
          turnTime=0
        }
      }
      
      yVel+=0.3
      if isCollisionBottom(1)
        yVel=0
      if isCollisionLeft(1)
        xVel*=-1
      if isCollisionRight(1)
        xVel*=-1
      if isCollisionSolid()
        y-=2
      if xVel>0
        image_xscale=1
      else
        image_xscale=-1
      moveTo(xVel,yVel)
      if y>room_height+24
      {
        if questType>0
          enemyQuest(questType)
        instance_destroy()
      }
    }
    else //Phase in
    {
      if introAnim=0
      {
        if x>oPlayer1.x {image_xscale=-1}
        detectDistX=264
        detectDistY=200
        visible=1
        introAnim=1
      }
      else if introAnim=1
      {
        phase+=0.025
        amplitude-=2
        if amplitude<=1 {introAnim=10}
      }
      else if introAnim>=10
      {
        introAnim+=1
        if introAnim>=20
        {
          image_speed=0.45
          bCanTakeDamage=true
          bCanDealDamage=true
          introAnim=100
        }
      }
    }
  }
  else if life<=0
  {
    for(i=0;i<12;i+=1)
    {
      tEffect=instance_create(x+random_range(-22,22),y-1-random(21),oEffectB)
      tEffect.type=3; tEffect.image_speed=0; tEffect.image_index=choose(0,1); tEffect.sprite_index=sPauseM_SkillLv
      tEffect.direction=random(360); tEffect.speed=random(1)+1; tEffect.fadeSpd=0.03;
      tEffect.AccelX=0; tEffect.AccelY=0; tEffect.newBlend=-1; tEffect.followID=-1; tEffect.rotation=0
    }
    instance_destroy()
  }
  enemyStepEvent()
}
